const d = $input.first().json;
const sqft = d.sqft || 1000;

// Per-sqft cost bands by condition
const bands = { cosmetic: 15, light: 28, moderate: 45, heavy: 65, gut: 90 };
const condition = (d.condition || 'moderate').toLowerCase();
const ppsf = bands[condition] || bands.moderate;

// Line-item estimates
const items = [
  { category: 'Roof', cost: d.roof_needed ? (sqft * 0.15 * 3.50) : 0 },
  { category: 'HVAC', cost: d.hvac_needed ? 6500 : 0 },
  { category: 'Electrical', cost: d.electrical_needed ? 4500 : 0 },
  { category: 'Plumbing', cost: d.plumbing_needed ? 3500 : 0 },
  { category: 'Flooring', cost: sqft * (d.flooring_ppsf || 4.50) },
  { category: 'Kitchen', cost: d.kitchen_remodel ? 12000 : 2500 },
  { category: 'Bathrooms', cost: (d.baths || 1) * (d.full_bath_remodel ? 6500 : 1800) },
  { category: 'Windows', cost: (d.windows || 0) * 400 },
  { category: 'Paint (Interior)', cost: sqft * 1.25 },
  { category: 'Paint (Exterior)', cost: sqft * 0.80 },
  { category: 'Landscaping', cost: 1500 },
  { category: 'Permits & Inspections', cost: 2000 },
  { category: 'Contingency (10%)', cost: 0 }
];

const base = items.slice(0, -1).reduce((s, i) => s + i.cost, 0);
const contingency = base * 0.10;
items[items.length - 1].cost = contingency;
const total = base + contingency;

return [{ json: { sqft, condition, base_rehab: Math.round(base), contingency: Math.round(contingency), total_rehab: Math.round(total), price_per_sqft: Math.round(total / sqft), line_items: items.filter(i => i.cost > 0) } }];
